custom_css:
[selector='Bg-Body'] {
    background-color: #FFFFFF;
    border: 1px solid #D7DDE5;
    border-radius: 16px;
    padding: 40px 40px 60px 40px;
    /*min-height: 324px;*/
    box-shadow:0px 3px 5px 0px #e7e7e7;
}
[selector='TabMenuActive']{
    border-bottom: 3px solid #2773F3;
}
.TextActive{
    color: #2773F3;
    text-align: center;
    font-size: 15px;
    font-weight: 600;
}
.TextAll{
    color: #596372;
    text-align: center;
    font-size: 15px;
    font-weight: 400;
}
[selector='Bg-HeaderLine']{
    border-bottom: 1px solid #CDDDEE;
}
.TextTitle{
    color: #343434;
    font-size: 28px;
    font-weight: bold;
    font-family: 'Open Sans';
} 


/**/
 .search-box {
            position: relative;
            width: 100%;
        }
        .search-box input[type="text"] {
            width: 100%;
            padding: 10px 40px 10px 40px;
            border-radius: 6px;
            border: 1px solid #ccc;
            font-size: 16px;
        }
        .search-box .icon {
            position: absolute;
            left: 15px;
            top: 50%;
            transform: translateY(-50%);
            color: #aaa;
        }


[selector='Btn-Style'] .btn-primary {
    color: #fff;
    background-color: #2773F3;
    border-color: #2773F3;
    text-transform: capitalize !important;
}
[selector='Btn-Style'] .btn-primary:hover{
    color: #fff;
    background-color: #5e99fe;
    border-color: #5e99fe;
    text-transform: capitalize !important;
}
[selector='Btn-Style-Info'] .btn-info {
    color: #000000;
    background-color: #FFFFFF;
    border:1px solid #D7DDE5;
    text-transform: capitalize !important;
}
[selector='Btn-Style-Info'] .btn-info:hover{
    color: #000000;
    background-color: #D7DDE5;
    border-color: #D7DDE5;
    text-transform: capitalize !important;
}
/**Bg-Container***/

[selector='Bg-Container'] .saved-search-chart .chart-error h3 {
    display: none;
}
[selector='Bg-Container'] .saved-search-chart.mb-3 {
    margin-bottom: 0px !important;
}
.card.dashboard-card, [selector='Bg-Container'] {
    border-radius: 15px !important;
    border: 3px solid #fff !important;
    box-shadow: 0 0.5rem 1rem rgba(0,0,0,0.15)!important;
    margin-bottom: 3rem !important;
}
.card.dashboard-card .card-header, [selector='Bg-Container'] {
    background-color: #F9F9F9 !important;
}

[selector='Bg-Container'] .card{
    border-radius:15px !important; 
}

[selector='Bg-Form']  select {
    word-wrap: normal;
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: 1px solid #dddfe4;
    border-radius: 8px;
    color: #9FA8B5;
}
[selector='Bg-Form'] p {
    margin-top: 0;
    margin-bottom: 12px;
}
[selector='Bg-Form'] .form-group {
    color: #20243A;
    font-size: 14px;
    font-weight: 500;
}
